// ─── MAIN TAB ─────────────────────────────────────────────────────────────────
export function ProductionTab() {
  const { filteredProd, productionData, prodFilter, setProdFilter,
          addProduction, updateProduction, deleteProduction,
          importProductionCSV, productTypes, formatDate } = useData();

  const [showBatch, setShowBatch]   = useState(false);
  const [editId, setEditId]         = useState<string | null>(null);
  const [importResult, setImportResult] = useState<{ imported: number; skipped: string[] } | null>(null);
  const [filterItem, setFilterItem]     = useState<string[]>([]);
  const [confirmDelete, setConfirmDelete] = useState<string | null>(null);

  const displayRows = useMemo(() => filteredProd
    .filter(e => {
      if (filterItem.length === 0) return true;
      return filterItem.some(typeCode => {
        const pt = productTypes.find(t => t.code === typeCode);
        return pt ? e.code.startsWith(pt.prefix) : false;
      });
    })
    .sort((a, b) => b.date.localeCompare(a.date)),
  [filteredProd, filterItem, productTypes]);

  // KPIs
  const { totalSets, commSets, extraCovers, extraFrames } = useMemo(() => {
    const groups = new Map<string, { cover: number; frame: number; isComm: boolean }>();
    displayRows.forEach(e => {
      const k = e.code;
      if (!groups.has(k)) groups.set(k, { cover: 0, frame: 0, isComm: getCategoryFromCode(e.code) === 'commercial' });
      const r = groups.get(k)!;
      r.cover += e.coverQty;
      r.frame += e.frameQty;
    });
    let totalSets = 0, commSets = 0;
    groups.forEach(r => {
      const s = Math.min(r.cover, r.frame);
      totalSets += s;
      if (r.isComm) commSets += s;
    });
    const allGroups = new Map<string, { cover: number; frame: number }>();
    productionData.forEach(e => {
      const k = e.code;
      if (!allGroups.has(k)) allGroups.set(k, { cover: 0, frame: 0 });
      const r = allGroups.get(k)!;
      r.cover += e.coverQty;
      r.frame += e.frameQty;
    });
    let extraCovers = 0, extraFrames = 0;
    allGroups.forEach(r => {
      const s = Math.min(r.cover, r.frame);
      extraCovers += r.cover - s;
      extraFrames += r.frame - s;
    });
    return { totalSets, commSets, extraCovers, extraFrames };
  }, [displayRows, productionData]);

  const totalWt = displayRows.reduce((s, e) => s + e.totalWeightKg, 0);

  const chartData = useMemo(() => {
    const days: { label: string; value: number }[] = [];
    for (let i = 13; i >= 0; i--) {
      const d = new Date(Date.now() - i * 86400000);
      const iso = d.toISOString().split('T')[0];
      const label = `${d.getDate()}/${d.getMonth() + 1}`;
      const value = groupedSets(productionData.filter(e => e.date === iso));
      days.push({ label, value });
    }
    return days;
  }, [productionData]);

  function handleImport(e: React.ChangeEvent<HTMLInputElement>) {
    const file = e.target.files?.[0]; if (!file) return;
    const reader = new FileReader();
    reader.onload = ev => { setImportResult(importProductionCSV(ev.target?.result as string)); };
    reader.readAsText(file);
    e.target.value = '';
  }

  async function handleBatchSubmit(rows: PendingProdRow[]) {
    await Promise.all(rows.map(r => addProduction(r.date, r.code, r.cover, r.frame)));
    setShowBatch(false);
  }

  const editEntry = editId ? productionData.find(e => e.id === editId) : undefined;

  return (
    <div>
      {/* KPI Cards */}
      <div className="grid grid-cols-2 md:grid-cols-4 gap-3 mb-5">
        <KpiCard label="Total Sets" value={totalSets.toLocaleString()} />
        <KpiCard label="Total Weight" value={`${(totalWt / 1000).toFixed(2)} T`} sub={`${totalWt.toLocaleString()} kg`} accent="#4ade80" />
        <KpiCard label="Commercial Sets" value={commSets.toLocaleString()} accent="#60a5fa" />
        <KpiCard label="Imbalance" value={`${extraCovers}C / ${extraFrames}F`}
          sub="Extra covers / frames" accent={extraCovers + extraFrames > 0 ? '#f59e0b' : '#4ade80'} />
      </div>

      {/* 14-day chart */}
      <div className="rounded-xl border border-[#2a2f3e] p-4 mb-5" style={{ background: '#151824' }}>
        <div className="text-xs text-gray-400 font-mono mb-2 uppercase tracking-widest">14-Day Production (Sets)</div>
        <BarChart data={chartData} color="#f59e0b" />
      </div>

      {/* Filters */}
      <div className="flex items-center gap-3 flex-wrap mb-4">
        <PeriodFilter filter={prodFilter} onChange={setProdFilter} />
        <div className="flex gap-1 flex-wrap">
          {productTypes.map(t => (
            <button key={t.code}
              onClick={() => setFilterItem(prev =>
                prev.includes(t.code) ? prev.filter(x => x !== t.code) : [...prev, t.code])}
              className={`px-2 py-0.5 rounded text-xs font-mono border transition-colors ${
                filterItem.includes(t.code) ? 'text-black border-transparent' : 'text-gray-400 border-[#2a2f3e] hover:border-gray-500'
              }`}
              style={filterItem.includes(t.code) ? { background: t.color } : {}}>
              {t.code}
            </button>
          ))}
          {filterItem.length > 0 && (
            <button onClick={() => setFilterItem([])}
              className="px-2 py-0.5 rounded text-xs text-gray-500 hover:text-gray-300 border border-[#2a2f3e]">
              Clear
            </button>
          )}
        </div>
      </div>

      {/* Toolbar */}
      <div className="flex gap-2 mb-4 flex-wrap">
        <button onClick={() => { setShowBatch(true); setEditId(null); }}
          disabled={showBatch}
          className="flex items-center gap-1.5 px-3 py-1.5 bg-amber-500 hover:bg-amber-400 disabled:opacity-50 text-black text-sm rounded font-medium transition-colors">
          <span>+</span> Add Production
        </button>
        <label className="flex items-center gap-1.5 px-3 py-1.5 bg-[#2a2f3e] hover:bg-[#363d52] text-gray-300 text-sm rounded font-medium cursor-pointer transition-colors">
          ↑ Import CSV
          <input type="file" accept=".csv" onChange={handleImport} className="hidden" />
        </label>
      </div>

      <ImportBanner result={importResult} onDismiss={() => setImportResult(null)} />

      {/* Batch Entry Panel */}
      {showBatch && !editId && (
        <BatchProductionPanel
          onSubmitAll={handleBatchSubmit}
          onCancel={() => setShowBatch(false)}
        />
      )}

      {/* Edit Form (single entry) */}
      {editId && editEntry && (
        <ProductionEditForm
          initial={editEntry}
          onSave={(date, code, cover, frame) => {
            updateProduction(editId, date, code, cover, frame);
            setEditId(null);
          }}
          onCancel={() => setEditId(null)}
        />
      )}

      {/* Delete confirmation */}
      {confirmDelete && (
        <div className="fixed inset-0 bg-black/60 flex items-center justify-center z-50">
          <div className="bg-[#151824] border border-[#2a2f3e] rounded-xl p-6 max-w-sm w-full mx-4">
            <div className="text-base font-semibold mb-2 text-white">Delete entry?</div>
            <div className="text-sm text-gray-400 mb-4">This cannot be undone.</div>
            <div className="flex gap-3">
              <button onClick={() => { deleteProduction(confirmDelete); setConfirmDelete(null); }}
                className="px-4 py-2 bg-red-600 hover:bg-red-500 text-white text-sm rounded">Delete</button>
              <button onClick={() => setConfirmDelete(null)}
                className="px-4 py-2 bg-[#2a2f3e] text-gray-300 text-sm rounded">Cancel</button>
            </div>
          </div>
        </div>
      )}

      {/* Table */}
      <div className="overflow-x-auto rounded-xl border border-[#2a2f3e]">
        <table className="w-full text-xs font-mono border-collapse">
          <thead>
            <tr className="text-gray-400 border-b border-[#2a2f3e]" style={{ background: '#1a1f2e' }}>
              {['Date','Code','Item','Size','Cap','Cover','Frame','Set','+Cover','+Frame','Set Wt (kg)','Total Wt (kg)',''].map(h => (
                <th key={h} className="px-3 py-2 text-left whitespace-nowrap">{h}</th>
              ))}
            </tr>
          </thead>
          <tbody>
            {displayRows.length === 0 && (
              <tr><td colSpan={13} className="px-4 py-8 text-center text-gray-600">No entries for selected period</td></tr>
            )}
            {displayRows.map(e => (
              <tr key={e.id} className="border-b border-[#1e2433] transition-colors hover:bg-[#1a1f2e]">
                <td className="px-3 py-1.5 text-gray-400">{formatDate(e.date)}</td>
                <td className="px-3 py-1.5 text-amber-400">{e.code}</td>
                <td className="px-3 py-1.5 text-gray-300">{e.item}</td>
                <td className="px-3 py-1.5 text-gray-400">{e.size}</td>
                <td className="px-3 py-1.5 text-gray-400">{e.capacity}</td>
                <td className="px-3 py-1.5 text-gray-300">{e.coverQty}</td>
                <td className="px-3 py-1.5 text-gray-300">{e.frameQty}</td>
                <td className="px-3 py-1.5 text-green-400 font-bold">{e.setQty}</td>
                <td className={`px-3 py-1.5 ${e.extraCover > 0 ? 'text-amber-400 font-bold' : 'text-gray-600'}`}>{e.extraCover}</td>
                <td className={`px-3 py-1.5 ${e.extraFrame > 0 ? 'text-amber-400 font-bold' : 'text-gray-600'}`}>{e.extraFrame}</td>
                <td className="px-3 py-1.5 text-gray-300">{e.setWeightKg.toFixed(2)}</td>
                <td className="px-3 py-1.5 text-gray-300">{e.totalWeightKg.toFixed(2)}</td>
                <td className="px-3 py-1.5">
                  <div className="flex gap-2">
                    <button onClick={() => { setEditId(e.id); setShowBatch(false); }}
                      className="text-blue-400 hover:text-blue-300 text-xs">Edit</button>
                    <button onClick={() => setConfirmDelete(e.id)}
                      className="text-red-400 hover:text-red-300 text-xs">Del</button>
                  </div>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
      <div className="mt-2 text-xs text-gray-600 font-mono text-right">{displayRows.length} entries</div>
    </div>
  );
}
